33	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (100 + 10 + 5 = 115)");
34	  it.todo("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 + 10 + 5 = 195)");
35	
36	  // --- Modifier scope: cursed applies only to the cursed item in a multi-item policy ---
37	  it.todo("cursed sword + plain amulet (newcomer): item bases 100+60=160; curse 50 (on sword only); first ins 21 (10% of 210); +5 fee = 236 G");
