41	  it.todo("customer's second quote (plain sword): 100 + 10 first insurance - 15 follow-up + 5 fee = 100 G");
42	
43	  // --- Integration examples ---
44	  it.todo("Newcomer with cursed sword (steel, ench 3): premium 165 G");
45	  it.todo("Long-standing customer (3 yrs) second contract, cursed sword (steel, ench 7): premium 160 G");
46	  it.todo("first insurance surcharge applies to each item even for follow-up contract");
47	
48	  // --- Rounding in MHPCO favor ---
49	  it.todo("premium yielding 197.5 G → 198 G (rounded up)");
50	
51	  // --- Claim: standard reimbursement ---
52	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
53	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G");
54	
55	  // --- Claim: high enchantment clause ---
56	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
57	
58	  // --- Claim: dragon material clause ---
59	  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
60	
61	  // --- Claim: dragon precedence over high enchantment ---
62	  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins per spec interpretation: 500-100)");
63	  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G");
